    Ok(())
}

use std::collections::BinaryHeap;
use std::cmp::{Eq, PartialEq, Ord, PartialOrd};
use std::sync::{Arc, Mutex};
use tokio::time::{self, Duration};

#[derive(Debug, Eq, PartialEq, Clone)]
struct EmailPayload {
    priority: i32,
    content: String,
}

impl Ord for EmailPayload {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.priority.cmp(&other.priority)
    }
}

impl PartialOrd for EmailPayload {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl From<EmailPayload> for BinaryHeap<EmailPayload> {
    fn from(item: EmailPayload) -> Self {
        BinaryHeap::from([item])
    }
}

struct EmailQueue {
    queue: Mutex<BinaryHeap<EmailPayload>>,
}

impl EmailQueue {
    fn new() -> Arc<Self> {
        Arc::new(EmailQueue { queue: Mutex::new(BinaryHeap::new()) })
    }

    async fn enqueue(&self, payload: EmailPayload) {
        let mut guard = self.queue.lock().unwrap();
        guard.push(payload.clone());
        println!("Enqueued message with priority: {}", payload.priority);
    }

    fn process_next(&self) -> Option<EmailPayload> {
        let mut guard = self.queue.lock().unwrap();
        if let Some(payload) = guard.pop() {
            println!("Dispatching message...");
            Some(payload)
        } else {
            None
        }
    }
}

async fn worker_loop(queue: Arc<EmailQueue>) {
    let mut interval = time::interval(Duration::from_millis(500));
    loop {
        interval.tick().await;
        if let Some(payload) = queue.process_next() {
            println!("n--- Processing Payload ---nPriority: {}
Content Preview: {:.30}...
--------------------------n", payload.priority, payload.content);
            tokio::time::sleep(Duration::from_millis(150)).await;
        }
    }
}

#[tokio::main]
async fn main() {
    let queue = EmailQueue::new();

    let _worker = tokio::spawn(worker_loop(Arc::clone(&queue)));

    time::sleep(Duration::from_millis(100)).await;
    queue.enqueue(EmailPayload { priority: 5, content: "Urgent system alert payload".to_string() }).await;
    queue.enqueue(EmailPayload { priority: 1, content: "Low importance routine status update".to_string() }).await;
    time::sleep(Duration::from_millis(300)).await;
    queue.enqueue(EmailPayload { priority: 10, content: "Critical infrastructure dump payload".to_string() }).await;

    tokio::time::sleep(Duration::from_secs(4)).await;
}

use std::collections::HashMap;
use std::fmt::Write;

struct JobContext {
    data: HashMap<String, String>,
    result: String,
}

impl JobContext {
    fn new() -> Self {
        JobContext { data: HashMap::new(), result: String::new() }
    }
}

fn validate_job(context: &mut JobContext) -> Result<(), String> {
    if context.data.get("api_key").is_none() || context.data.get("user_id").unwrap().is_empty() {
        return Err("Missing required headers for job execution".to_string());
    }
    Ok(())
}

fn transform_payload(context: &mut JobContext) -> Result<(), String> {
    let user_id = context.data.get("user_id").unwrap().clone();
    if !user_id.contains("::") {
        return Err("Invalid user ID format for transformation".to_string());
    }
    context.data.insert("transformed_user".to_string(), format!("Processed: {}", user_id));
    Ok(())
}

fn run_job(mut context: JobContext) -> String {
    match validate_job(&mut context) {
        Ok(_) => match transform_payload(&mut context) {
            Ok(_) => write!(&mut context.result, "Job completed successfully for user {}.", context.data.get("transformed_user").unwrap()).unwrap(),
            Err(e) => write!(&mut context.result, "Transformation failed: {}", e).unwrap(),
        },
        Err(e) => write!(&mut context.result, "Validation failed: {}", e).unwrap(),
    }
    context.result
}

fn main() {
    let mut initial_data = HashMap::new();
    initial_data.insert("api_key".to_string(), "secure-token-123".to_string());
    initial_data.insert("user_id".to_string(), "app::worker:job_xyz".to_string());

    let job_context = JobContext::new();
    let final_result = run_job(JobContext { data: initial_data, result: String::new() });
    println!("Final Pipeline Result: {}", final_result);
}
